package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Constructor;
import java.util.Collections;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CartTest {

  private Cart cart;
  private List<LineItem> emptyLineItems;

  @BeforeEach
  void setUp() throws Exception {
    emptyLineItems = Collections.emptyList();
    Constructor<Cart> constructor = Cart.class.getDeclaredConstructor(List.class, String.class, String.class);
    constructor.setAccessible(true);
    cart = constructor.newInstance(emptyLineItems, "TestBuyer", "1234-5678-9012-3456");
  }

  @Test
  void testGetBuyerName() {
    assertEquals("TestBuyer", cart.getBuyerName());
  }
}
